import React from 'react';
import { clsx } from 'clsx';
import { useScrollReveal } from '../../hooks';

const SectionHeader = ({
  number,
  title,
  titleHighlight,
  description,
  dark = false,
  className,
}) => {
  const [ref, isVisible] = useScrollReveal();

  return (
    <div
      ref={ref}
      className={clsx(
        'grid grid-cols-[auto_1fr] gap-8 md:gap-12 items-start mb-16 md:mb-20',
        'opacity-0 translate-y-10 transition-all duration-700 ease-out-expo',
        isVisible && 'opacity-100 translate-y-0',
        className
      )}
    >
      <span
        className={clsx(
          'font-serif italic text-base pt-2',
          dark ? 'text-gold' : 'text-gold'
        )}
      >
        {number}
      </span>
      <div className="max-w-[700px]">
        <h2 className="text-display-lg font-medium mb-6">
          {title}{' '}
          {titleHighlight && (
            <span className="font-serif italic">{titleHighlight}</span>
          )}
        </h2>
        {description && (
          <p
            className={clsx(
              'text-lg leading-relaxed max-w-[500px]',
              dark ? 'text-white/50' : 'text-warm-gray'
            )}
          >
            {description}
          </p>
        )}
      </div>
    </div>
  );
};

export default SectionHeader;
